<template>
  <nav class="side-menu__container">
    <input type="text" placeholder="Search" class="input__text">
    <ul class="side-menu__filter-list">
      <li class="side-menu__filter-dropdown" v-for="(term, index, key) in data" :key="key">
        <span class="side-menu__filter-term" @click="toggleDropdown">{{term.name}}</span>
        <div class="side-menu__form-wrapper">
          <form class="side-menu__filter-form" action="submit" name="division">
            <div class="side-menu__form-item" v-for="(values, index, key) in term.values" :key="key">
              <input type="radio" :value="values" name="division" :id="values" @change="addValueToArray(values)">
              <label class="side-menu__form-label" for="division">{{values}}</label>
            </div>
          </form>
        </div>
      </li>
    </ul>
  </nav>
</template>

<script>
export default {
  name: 'SideMenu',
  props: {
    data: {
      type: Object,
      required: true
    }
  },
  data () {
    return {
      valuesArray: []
    }
  },
  methods: {
    toggleDropdown (e) {
      e.target.parentNode.classList.toggle('dropdown--opened')
    },
    addValueToArray (value) {
      console.log(value)
      this.valuesArray.push(value)
    }
  }
}
</script>
